<template>
	<div class="timer-test">
		<div class="item debounce">
			<div class="title">debounce 等待执行，期间再点击，就不断等待，直到防抖时间到了再生效</div>
			<div class="button"
				v-on:mousedown='debounceAdd1'>点击执行防抖加一</div>
			<div class="test">{{debounceTime1}}</div>
		</div>
		<div class="item debounce">
			<div class="title">debounce 立马执行，防抖时间过后，点击再立马执行</div>
			<div class="button"
				v-on:mousedown='debounceAdd2'>点击执行防抖加一</div>
			<div class="test">{{debounceTime2}}</div>
		</div>
		<div class="item throttle">
			<div class="title">throttle</div>
			<div class="button"
				v-on:mousedown='throttleAdd'>点击执行节流加一</div>
			<div class="test">{{throttleTime}}</div>
		</div>
	</div>
</template>

<script>
	import debounce from '../../utils/timer/debounce.js'
	import throttle from '../../utils/timer/throttle.js'

	export default {
		data(){
			return {
				debounceTime1: 0,
				debounceTime2: 0,
				throttleTime: 0,
			}
		},
		methods: {
			debounceAdd1: debounce((function(){
				this.debounceTime1 ++;
			}), 2000),
			debounceAdd2: debounce((function(){
				this.debounceTime2 ++;
			}), 2000, true),
			throttleAdd: throttle((function(){
				this.throttleTime ++;
			}), 2000),
		}
	}
</script>

<style lang="less">
	.timer-test{
		width: 100%;
		height: 100%;
		>.item{
			>.button{
				user-select: none;
			}
		}
	}
</style>